#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long H,X,Y; // use long long for up to 1e18 (fits in 64‑bit)
        scanf("%lld %lld %lld", &H, &X, &Y);
        if (X > Y) printf("1\n");
        else printf("0\n");
    }
    return 0;
}

